INSERT INTO ingredient_knowledge (id, name, category, species_safe, safety_notes, nutrition_info, content_text) VALUES
('2c423ad2-ea12-4dc7-9481-fbc65643a6c3', 'chicken breast (boneless, skinless)', 'protein', '{"DOG","CAT"}',
 'Cook thoroughly; serve plain (no salt, onion/garlic, sauces). Remove all bones. Prefer skinless to limit fat; introduce gradually to avoid GI upset.',
 'Qualitative: lean animal protein. Approx kcal/100g derived from USDA SR Legacy entry for chicken (light meat, meat only; raw basis) ≈113.6 kcal/100g; cooked values will differ due to moisture loss.',
 'Chicken breast is commonly used in home-prepared bland diets and as a lean, cooked meat option for both dogs and cats. Keep it unseasoned and fully cooked; never feed bones. Skinless portions help reduce fat load for pets prone to pancreatitis or obesity.'),

('2dd89e66-bee8-4188-98f5-3358d5072e1d', 'turkey breast (boneless, skinless)', 'protein', '{"DOG","CAT"}',
 'Cook thoroughly; keep unseasoned. Remove skin to reduce fat; avoid deli/processed turkey due to salt and additives.',
 'Qualitative: lean animal protein. Approx kcal/100g from USDA SR Legacy turkey breast roasted entry ≈147.1 kcal/100g.',
 'Turkey breast is often recommended as a bland, easily digested lean protein in short-term home-prepared feeding. Use plain, cooked, skinless meat and avoid processed versions that are high in salt.'),

('3b5bd638-5d21-4985-bfa0-6ea016a9196c', 'chicken thigh (boneless, skinless)', 'protein', '{"DOG","CAT"}',
 'Cook thoroughly and remove skin; thighs are typically fattier than breast, so portion carefully for pets with pancreatitis risk or weight management needs.',
 'Qualitative: higher-fat poultry cut vs breast (varies by trimming). Per-100g values: unspecified.',
 'Chicken thigh is used in structured home-cooked recipes (including feline-focused formulations). Because dark meat is generally higher in fat than breast, prefer skinless, cooked thigh and adjust portions based on the pet''s condition and veterinary advice.'),

('f2ce174b-4c75-4cf9-94a5-73f7f9493818', 'chicken drumstick (meat only, deboned)', 'protein', '{"DOG","CAT"}',
 'Cook thoroughly; debone completely—cooked bones splinter. Remove skin to reduce fat. Avoid seasoning.',
 'Qualitative: poultry dark cut; fat content varies. Approx kcal/100g derivation from USDA SR Legacy drumstick (meat+skin, stewed) entry ≈204.3 kcal/100g; meat-only/skinless will differ.',
 'Chicken drumstick meat can be used as a home-cooked protein if fully cooked, plain, and completely deboned. Do not feed cooked bones. Skin removal reduces fat; this matters for GI sensitivity and pancreatitis risk.'),

('5e112aa6-8454-4258-a393-ac186d20180a', 'ground turkey (lean)', 'protein', '{"DOG","CAT"}',
 'Cook thoroughly and drain excess fat. Avoid seasoning. Introduce gradually; monitor stool quality.',
 'Qualitative: animal protein; fat varies by leanness. Approx kcal/100g derivation from USDA SR Legacy ''ground turkey 93% lean, pan-broiled'' ≈212.9 kcal/100g.',
 'Lean ground turkey is listed as a permitted protein option in veterinary bland-diet instructions and appears in structured home-cooked recipe tools. Use plain, fully cooked meat and drain fat to improve digestibility.'),

('e0a35536-30af-49e9-b39c-9b36f8b7676b', 'ground beef (lean)', 'protein', '{"DOG","CAT"}',
 'Cook thoroughly and drain/rinse to reduce fat; keep unseasoned. Avoid onion/garlic powders commonly used in human mince preparations.',
 'Qualitative: protein + iron; fat varies. Approx kcal/100g derivation from USDA SR Legacy ''ground beef 90% lean, cooked'' ≈216.5 kcal/100g.',
 'Lean ground beef is used in veterinary-supervised home-cooked formulations. The key safety point is to cook it fully and reduce fat, since high-fat meals can trigger GI upset or pancreatitis in susceptible dogs.'),

('a970e88f-e2aa-4410-a700-1136b3601e95', 'pork loin (lean cut)', 'protein', '{"DOG","CAT"}',
 'Cook thoroughly; feed plain. Prefer lean loin over fatty/processed pork (bacon/ham). Avoid salty cured meats.',
 'Qualitative: protein; fat depends on trimming. Approx kcal/100g derivation from USDA SR Legacy ''pork loin top loin roast, separable lean only, cooked'' ≈172.9 kcal/100g.',
 'Lean pork loin appears in structured home-cooked recipe formulations and is also listed as an acceptable lean cooked meat to share in small amounts when unseasoned. Prioritise lean, cooked loin and avoid processed pork products.'),

('fb6d161b-f60f-4e1c-8155-7b17cbb2b2f1', 'duck breast (meat only)', 'protein', '{"DOG","CAT"}',
 'Cook thoroughly; remove skin (duck skin is very fatty). Keep unseasoned; debone.',
 'Qualitative: richer/fattier poultry; high calorie density if skin-on. Per-100g values: unspecified.',
 'Duck breast is used in veterinary nutritionist recipe-builder outputs (often as a novel protein option). For most pets, the main safety issue is fat load; choose cooked, skinless duck breast in measured amounts.'),

('2d5a6148-079b-40f7-81f0-0c0df6b65205', 'lamb mince (ground lamb)', 'protein', '{"DOG","CAT"}',
 'Cook thoroughly; drain fat; feed plain. Lamb can be rich—portion carefully for pancreatitis-prone dogs.',
 'Qualitative: higher fat than many poultry cuts; provides protein and iron. Per-100g values: unspecified.',
 'Ground lamb appears in structured home-cooked recipe formulations. It can be useful as an alternative protein but is often calorie-dense; cooked, drained preparations are generally safer for digestion.'),

('c3fa2556-6b29-4d26-937a-3b06e43d4b60', 'rabbit (cooked)', 'protein', '{"DOG","CAT"}',
 'Cook thoroughly and serve plain; remove bones. Consider as a novel protein—introduce slowly if the pet has a sensitive GI tract.',
 'Qualitative: typically lean novel protein. Per-100g values: unspecified.',
 'Rabbit appears as a protein ingredient in veterinary nutritionist recipe-builder outputs, commonly used when owners need a novel protein. As with any meat, cook fully and serve unseasoned with bones removed.'),

('d5b3646b-0d6f-4a28-9b02-f3913d744b7a', 'cod (white fish fillet)', 'seafood', '{"DOG","CAT"}',
 'Cook thoroughly; remove all bones. Keep plain (no batter, no seasoning).',
 'Qualitative: lean fish protein. Approx kcal/100g derivation from USDA SR Legacy ''cod, Pacific, raw'' ≈69.0 kcal/100g (raw basis; cooked differs).',
 'White fish fillet features in bland-diet guidance as a gentle protein option. Use cooked, boneless fillets without salt, oils, or coatings.'),

('27f234ca-7896-4bf5-820e-ca6f9c238e38', 'tilapia (white fish fillet)', 'seafood', '{"DOG","CAT"}',
 'Cook thoroughly; remove bones; serve plain.',
 'Qualitative: lean fish protein. Approx kcal/100g derivation from USDA SR Legacy ''tilapia, raw'' ≈95.7 kcal/100g (raw basis; cooked differs).',
 'Tilapia is used as a fish option in structured home-cooked recipe substitutions. The main safety principles are full cooking, bone removal, and avoiding seasoning or oils.'),

('61b69a20-5201-40bd-aab2-a66a71c3c720', 'salmon (cooked)', 'seafood', '{"DOG","CAT"}',
 'Cook thoroughly; debone. Avoid raw salmon for dogs due to salmon poisoning disease risk in endemic regions; seek urgent veterinary care if suspected exposure.',
 'Qualitative: fatty fish providing omega-3s. Approx kcal/100g derivation from USDA SR Legacy wild coho salmon cooked entry ≈183.5 kcal/100g.',
 'Cooked salmon is used in structured home-cooked recipes and can provide omega-3 fatty acids. It must be fully cooked and deboned; raw salmon can be dangerous to dogs in areas where salmon poisoning disease occurs.'),

('5fb26e34-5f01-4649-8ac2-4850c5604819', 'tuna (plain; low-salt; preferably in water)', 'seafood', '{"DOG","CAT"}',
 'Treat-only: choose tuna in water with no added salt, flavours, or onion. Limit frequency due to nutritional imbalance risk if used as main food; consider mercury exposure as a practical constraint.',
 'Qualitative: high-protein fish; some forms are calorie-dense if packed in oil. Approx kcal/100g derivation from USDA SR Legacy skipjack tuna cooked entry ≈131.8 kcal/100g.',
 'Plain tuna can be an occasional enhancer for cats (and dogs) but should not form the bulk of the diet. Select simple preparations and feed sparingly to avoid imbalances.'),

('a44db08b-0f97-4c14-85ac-2dcb533e84b5', 'sardines (plain; low-salt; preferably in water)', 'seafood', '{"DOG","CAT"}',
 'Use plain sardines (avoid brine/oil with salt). Treat-only; account for fat load and sodium. Check for bones depending on product.',
 'Qualitative: oily fish providing omega-3s; calorie density varies by packing medium. Per-100g values: unspecified.',
 'Sardines are commonly discussed as an occasional oily-fish treat for cats (and sometimes dogs). Use plain, low-salt options and keep portions small.'),

('f36474b5-1b70-4c52-9efc-a4542dedbf4d', 'chicken liver', 'organ', '{"DOG","CAT"}',
 'Cook thoroughly; feed in small, measured amounts only. Chronic high-liver feeding can cause vitamin A toxicosis (particularly in cats).',
 'Qualitative: nutrient-dense organ (vitamin A, B vitamins, minerals). Per-100g values: unspecified; vitamin A overload is the key constraint.',
 'Chicken liver appears in structured home-cooked formulations but must be carefully limited. Liver is highly nutrient-dense; overfeeding (especially chronically) can lead to vitamin A toxicity.'),

('0f658997-69a2-4cf8-9e01-cc3181aad926', 'chicken heart', 'organ', '{"DOG","CAT"}',
 'Cook thoroughly; serve plain. Use as part of an overall balanced recipe rather than as the sole protein source.',
 'Qualitative: "muscle organ" providing protein; micronutrient profile differs from liver. Per-100g values: unspecified.',
 'Chicken heart appears in veterinary nutritionist recipe-builder outputs as a permissible animal ingredient. As with all animal-derived items, cook thoroughly and keep the overall diet balanced.'),

('c4e3b48c-8434-408c-9ad2-1d4fa9f8675d', 'egg (whole, cooked)', 'protein', '{"DOG","CAT"}',
 'Cook fully. Avoid raw eggs due to foodborne pathogen risk; some veterinary safety content warns about raw eggs in pets.',
 'Qualitative: complete animal protein with fat-soluble vitamins; energy varies by cooking method. Approx kcal/100g derivation from USDA SR Legacy egg (poached) ≈144.0 kcal/100g.',
 'Cooked egg is commonly included in bland-diet ingredient lists and can be a palatable protein source. It should be thoroughly cooked and fed as one component of a balanced plan.'),

('35bbd523-8e20-47cf-8c4a-d9c2f79332d3', 'cottage cheese (low-fat)', 'dairy', '{"DOG","CAT"}',
 'Use low-fat options and introduce slowly; some pets are lactose intolerant and may develop diarrhoea. Use as short-term bland-diet component or treat unless part of a formulated recipe.',
 'Qualitative: dairy protein + calcium; fat varies by type. Approx kcal/100g derivation from USDA SR Legacy cottage cheese lowfat (2% milkfat) ≈81.4 kcal/100g.',
 'Cottage cheese is repeatedly cited in bland-diet discussions (including academic veterinary resources). Choose low-fat cottage cheese and monitor tolerance, especially in cats and dogs prone to GI upset.'),

('79287f60-3ed2-4da7-a396-1cc38f36b3b2', 'cheddar cheese (small cubes only)', 'dairy', '{"DOG","CAT"}',
 'Treat-only. High fat and lactose can trigger GI upset; avoid flavoured cheeses or cheese containing onion/garlic.',
 'Qualitative: calorie-dense dairy. Approx kcal/100g derivation from USDA SR Legacy cheddar ≈403 kcal/100g.',
 'Cheese is listed as a pet-safe snack when offered sparingly. Because it is calorie-dense and can cause digestive upset in lactose-intolerant pets, use small cubes only and avoid seasoned varieties.'),

('85e98776-ac1b-47f5-a8a7-cefa4b5cefca', 'rice (white, cooked)', 'grain_starch', '{"DOG","CAT"}',
 'Cook thoroughly until soft; serve plain (no salt, onion, garlic). Typically used short-term in bland diets; not a complete diet by itself.',
 'Qualitative: easily digested carbohydrate. Approx kcal/100g derivation from USDA SR Legacy white rice cooked entry ≈129.7 kcal/100g.',
 'White rice is a classic carbohydrate component in bland diets (often paired with lean protein or cottage cheese). It should be cooked soft and fed plain.'),

('2bb83b57-042e-49f5-98ab-da5f6b58e503', 'rice (brown, cooked)', 'grain_starch', '{"DOG","CAT"}',
 'Cook very well; brown rice can be less digestible than white rice for some pets. Use plain; monitor stool.',
 'Qualitative: more fibre than white rice; per-100g values unspecified.',
 'Brown rice is included as an alternative carbohydrate in bland-diet guidance. It may not suit every pet during GI upset, so use cautiously and only as part of veterinary-directed feeding.'),

('4e5fa143-414a-4e52-9261-ea76c9e870aa', 'oats/oatmeal (plain, cooked)', 'grain_starch', '{"DOG","CAT"}',
 'Cook plain in water; avoid sweeteners, milk, and flavour packets. Use as a temporary bland carbohydrate or formulated recipe ingredient.',
 'Qualitative: carbohydrate + soluble fibre; per-100g values unspecified.',
 'Plain cooked oatmeal is listed among common bland-diet foods. It should be prepared without sugar or additives and used in appropriate portions for the pet''s size and condition.'),

('2a7aacf2-ccd8-4acb-9ef7-e291ea48d7c3', 'pasta (plain, cooked)', 'grain_starch', '{"DOG","CAT"}',
 'Cook plain; avoid sauces (many contain onion/garlic and salt). Use short-term for GI upset or within a recipe formulation.',
 'Qualitative: starch-based carbohydrate; per-100g values unspecified.',
 'Plain cooked pasta is included in bland-diet ingredient lists as a soft carbohydrate source. It should be served plain and in moderation.'),

('c1a993b2-f59d-4d1f-a8f5-0140d711ff2b', 'potato (boiled/baked, plain)', 'grain_starch', '{"DOG","CAT"}',
 'Cook fully; never feed green/raw potato. Serve plain (no butter, salt, onion/garlic).',
 'Qualitative: starchy carbohydrate. Approx kcal/100g derivation from USDA SR Legacy baked russet potato entry ≈95.0 kcal/100g (preparation-dependent).',
 'Boiled or baked potato is listed as a bland carbohydrate option. It should be fully cooked and served plain; avoid seasonings and any green/raw portions.'),

('b968c2b8-49e8-4f20-8e96-ceddfbcdb77b', 'sweet potato (cooked)', 'vegetable', '{"DOG","CAT"}',
 'Cook thoroughly; serve plain. Avoid sweetened/pie preparations. Introduce gradually due to fibre content.',
 'Qualitative: beta-carotene + fibre; calorie depends on preparation. Approx kcal/100g derivation from USDA SR Legacy baked sweet potato entry ≈90.4 kcal/100g (with salt; recipe varies).',
 'Sweet potato appears as a carbohydrate/vegetable component in structured home-cooked recipe outputs and is commonly used for palatability and fibre. Use plain, cooked sweet potato—no sugar, spices, or butter.'),

('64226401-1b81-4b01-9c7a-e0b6c2e34b93', 'pumpkin (plain canned, cooked)', 'vegetable', '{"DOG","CAT"}',
 'Use plain canned pumpkin (not pumpkin pie mix). Avoid spices/sugar. Start with small amounts; monitor stool.',
 'Qualitative: fibre and moisture; per-100g values unspecified.',
 'Cooked canned pumpkin is listed as a pet-safe vegetable snack and is also commonly used in temporary GI feeding plans. Use only plain pumpkin without spices or sweeteners.'),

('4f339e4a-0956-4233-a04a-fb238500e227', 'carrot', 'vegetable', '{"DOG","CAT"}',
 'Serve raw or cooked; cut into bite-size pieces to reduce choking risk. Avoid seasoning.',
 'Qualitative: fibre + carotenoids. Approx kcal/100g derivation from USDA SR Legacy raw carrots ≈40.6 kcal/100g.',
 'Carrots are repeatedly listed as a low-fat vegetable snack suitable for pets. They are useful for texture and fibre but should be cut small to prevent choking.'),

('a7ced1f0-fc5e-44b0-8cb6-4740f9302b3e', 'green beans', 'vegetable', '{"DOG","CAT"}',
 'Serve plain (raw or cooked), cut into small pieces. Avoid butter, salt, garlic/onion seasonings.',
 'Qualitative: low-calorie fibre; per-100g values unspecified.',
 'Green beans are listed as a pet-safe vegetable snack and are often used as a low-fat, low-calorie add-in. Keep preparation plain and portions appropriate.'),

('a7df54d6-0a92-4e26-96bd-9791a97b8d2b', 'broccoli', 'vegetable', '{"DOG","CAT"}',
 'Serve in small amounts; some pets develop gas/GI upset. Cut small; avoid seasoning.',
 'Qualitative: fibre + micronutrients. Approx kcal/100g derivation from USDA SR Legacy cooked frozen broccoli entry ≈28.3 kcal/100g (varies by preparation).',
 'Broccoli is listed as a pet-safe vegetable snack when offered plain and in bite-size pieces. Start small because brassica vegetables can cause digestive upset in some animals.'),

('f3a2bf8f-af40-42b7-9a7d-bb3c30343127', 'cauliflower', 'vegetable', '{"DOG","CAT"}',
 'Serve plain and in small amounts; may cause gas. Cut to bite size; avoid seasonings.',
 'Qualitative: fibre; per-100g values depend on variety. Approx kcal/100g derivation from USDA SR Legacy cauliflower (green, raw) entry ≈31.2 kcal/100g (as available in SR Legacy abridged list).',
 'Cauliflower is included in pet-safe vegetable snack lists. As with other cruciferous vegetables, small portions and careful observation help reduce GI side effects.'),

('0bb5b5a1-86c6-4aaa-9c46-245f54d95bd3', 'celery', 'vegetable', '{"DOG","CAT"}',
 'Cut into small pieces to prevent choking; fibrous strings can be difficult for some pets. Serve plain.',
 'Qualitative: low calorie, high water. Approx kcal/100g derivation from USDA SR Legacy cooked celery entry ≈18.0 kcal/100g.',
 'Celery is listed as a pet-safe snack option in small quantities and is primarily useful for water and crunch. Always chop finely for safety.'),

('1e6f1b46-488e-4a18-8a7f-6d5f6df2bc81', 'peas (green)', 'vegetable', '{"DOG","CAT"}',
 'Cook until soft for best digestibility; serve plain. Introduce gradually because legumes can cause gas in some pets.',
 'Qualitative: fibre and plant protein. Approx kcal/100g derivation from USDA SR Legacy green peas raw entry ≈80.7 kcal/100g (raw basis; cooked differs).',
 'Peas appear in structured home-cooked recipes (including feline recipes) as a vegetable component. They should be served plain and in moderation, with attention to individual tolerance.'),

('3d44a74b-726e-4ff3-8d87-359e89ea9b8b', 'cucumber', 'vegetable', '{"DOG","CAT"}',
 'Wash well; cut into small pieces. Feed as a watery snack; avoid pickled/salted cucumbers.',
 'Qualitative: high water, low energy; per-100g values unspecified.',
 'Cucumbers are listed as acceptable fruit/snack items for pets in small, bite-size pieces. They are mainly water and can be useful as a low-calorie treat component.'),

('bdf3efe0-d8b9-4b9c-92a0-2606d8f27d94', 'apple (no seeds/core)', 'fruit', '{"DOG","CAT"}',
 'Remove core and seeds; cut into bite-size pieces. Avoid sugary apple products.',
 'Qualitative: fibre; sugars present. Approx kcal/100g derivation from USDA SR Legacy raw apple (no skin) ≈48.2 kcal/100g.',
 'Apples are listed as pet-safe fruit when seeds/cores are removed and pieces are cut small. They are best treated as a snack rather than a diet base, given sugar content.'),

('b2cce4ad-4c25-4b49-a028-e560f6df1b9d', 'banana', 'fruit', '{"DOG","CAT"}',
 'Treat-only due to sugar and calorie load; offer small pieces and monitor stool.',
 'Qualitative: carbohydrate and potassium; per-100g values unspecified.',
 'Bananas are listed as acceptable pet-safe fruit in small quantities. Because they are relatively sugary and calorie-dense compared with many fruits, small portions are important.'),

('37e6d07b-b224-4760-9a40-ae94157b3ee4', 'blueberries', 'fruit', '{"DOG","CAT"}',
 'Wash and serve plain; small handful at most depending on pet size. Avoid sweetened products.',
 'Qualitative: antioxidant-associated compounds; per-100g values unspecified.',
 'Blueberries are included in pet-safe fruit lists and can be used as small training-style treats. Use plain berries and avoid sweetened canned preparations.'),

('24a8fcf8-f72e-429c-a62f-4d15c0d8a6f9', 'strawberries', 'fruit', '{"DOG","CAT"}',
 'Wash, remove leaves/stems; offer small pieces. Avoid sweetened strawberry products.',
 'Qualitative: vitamin C and fibre; per-100g values unspecified.',
 'Strawberries appear on pet-safe snack lists. They should be fed as a small, plain treat and prepared to remove stems and reduce choking risk.'),

('b6b14cf9-e8c2-43c6-9a3e-1dadc1a67cbe', 'popcorn (air-popped, plain)', 'treat', '{"DOG","CAT"}',
 'Only air-popped and plain—no butter, salt, or flavourings. Avoid unpopped kernels (choking/tooth hazard).',
 'Qualitative: mainly starch; per-100g values unspecified for plain air-popped in this report.',
 'Air-popped popcorn is listed as a pet-safe snack when kept plain and fed in small portions. The key hazards are added salt/fat and kernel choking risk.'),

('5f31adb4-e2af-4020-9300-7fc6b5b31e40', 'peanut butter (xylitol-free)', 'treat', '{"DOG","CAT"}',
 'Check label for xylitol (can be lethal to dogs). High-fat treat; use very small amounts.',
 'Qualitative: high calorie density and fat; per-100g values unspecified.',
 'Peanut butter is commonly used as an ingredient in pet-friendly recipes or to disguise medication, but it must be xylitol-free. Because it is high in fat, portions should be small.'),

('9d1f06cc-34ba-4c89-a2a0-6dac375f3bdc', 'canola oil (measured)', 'supplement', '{"DOG","CAT"}',
 'Use only in measured amounts within a formulated recipe; excess oil can cause diarrhoea and unwanted weight gain.',
 'Qualitative: concentrated fat source; per-100g values unspecified.',
 'Measured oils can appear in structured home-cooked recipes to meet energy and fatty-acid targets. Oil quantities should not be improvised; follow a formulated recipe to avoid excessive calorie intake.'),

('b3e06cbb-be76-44e0-9784-7cc4ca1f7fd7', 'fish oil (omega-3 supplement)', 'supplement', '{"DOG","CAT"}',
 'Dose matters; use veterinary guidance, especially for pets on anticoagulants or with pancreatitis history. Some pets develop GI upset.',
 'Qualitative: omega-3 fatty acids (EPA/DHA) supporting skin/coat and inflammation modulation; per-100g values not applicable as dosed supplement.',
 'Fish oil is a common veterinary supplement used to increase omega-3 intake. It should be selected and dosed under veterinary advice, with attention to the pet''s medical history and tolerance.'),

('84d241d2-745a-49ae-9960-42e1d85d7a19', 'taurine (supplement)', 'supplement', '{"CAT"}',
 'Cats have a strict dietary requirement for taurine; deficiency can be severe. Use only within a formulated diet plan and veterinary guidance.',
 'Qualitative: essential amino sulfonic acid for cats; per-100g values not applicable as dosed supplement.',
 'Taurine is a critical nutrient for cats, and homemade diets that omit adequate taurine risk serious health consequences. Taurine supplementation should follow veterinary nutrition guidance and a complete formulation.'),

('4dd2c897-58d2-45ed-829d-7ced919ba6cd', 'calcium carbonate (or equivalent calcium supplement)', 'supplement', '{"DOG","CAT"}',
 'Essential for balancing calcium and phosphorus in many home-cooked diets; incorrect dosing can be harmful. Use veterinary guidance and formulated recipes.',
 'Qualitative: mineral supplement; per-100g values not meaningful because dosed in grams/mg, not as food.',
 'Calcium supplementation is commonly required to balance home-prepared diets. Because mineral imbalances can be dangerous, calcium sources should be selected and dosed under veterinary guidance or via a professionally formulated recipe.'),

('facf2b1a-b1e7-46c6-922b-63a29960656c', 'onion', 'toxic/hazard', '{}',
 'Toxic to dogs and cats. Avoid all forms (raw, cooked, powders). Seek veterinary advice immediately if ingested.',
 'N/A (do not feed).',
 'Onion is explicitly listed among foods to keep away from pets. It is a high-risk ingredient in home cooking and must never be included in homemade pet recipes.'),

('eb47f1a1-35cb-44e0-b1b7-4af810f5f6f8', 'garlic', 'toxic/hazard', '{}',
 'Toxic/hazardous for dogs and cats; avoid all forms (raw, cooked, powders).',
 'N/A (do not feed).',
 'Garlic is listed among ingredients to keep away from pets. It should not appear in any homemade pet recipe, including broths, meat seasonings, or table scraps.'),

('1c6abdbe-d56e-4635-a15d-dfde064e2f00', 'grapes', 'toxic/hazard', '{}',
 'Potentially life-threatening toxicity reported in dogs; avoid entirely. If ingestion occurs, treat as an emergency.',
 'N/A (do not feed).',
 'Grapes are included on poison-control ''keep away'' lists for pets. Because the toxic mechanism and dose threshold are uncertain and severe outcomes are possible, exclusion from all pet foods is the prudent rule.'),

('a0e678a0-cf84-468d-9491-b05571e0e1a6', 'raisins', 'toxic/hazard', '{}',
 'Same hazard profile as grapes for dogs; avoid entirely (including baked goods). Treat ingestion as an emergency.',
 'N/A (do not feed).',
 'Raisins are explicitly listed with grapes as a keep-away item for pets. They should not be present in homemade treats, oatmeal mixes, baked goods, or trail mixes accessible to pets.'),

('cbd97d98-a7a6-467c-a0f8-dd8dfdaa6a76', 'chocolate', 'toxic/hazard', '{}',
 'Toxic to pets; severity depends on dose/type (dark/baking chocolate higher risk). Seek urgent veterinary care if ingested.',
 'N/A (do not feed).',
 'Chocolate is repeatedly listed as dangerous for pets and should never be used in homemade treats. It is a common household exposure risk and a key exclusion constraint in any pet-recipe product design.'),

('9ac8cf99-4c8f-47c7-8180-2f9298e2d02d', 'xylitol (and products containing xylitol)', 'toxic/hazard', '{}',
 'High-risk toxin for dogs; can cause rapid hypoglycaemia and liver injury. Check peanut butter, sweets, gum, and baked goods.',
 'N/A (do not feed).',
 'Xylitol-containing products are explicitly flagged as dangerous for pets, particularly dogs. Any homemade recipe workflow should include ''xylitol present?'' as a hard exclusion check.');
